mapper.select:
SELECT *
FROM thuc_hien_cong_doan
WHERE stt_cong_doan = #{sttCongDoan}
AND ma_du_an = #{maDuAn}

mapper.update:
UPDATE thuc_hien_cong_doan
SET vai_tro = #{vaiTro}
WHERE stt_cong_doan = #{sttCongDoan}
AND ma_du_an = #{maDuAn}
AND ma_nhan_vien = #{maNhanVien}

mapper.delete:
DELETE FROM thuc_hien_cong_doan
WHERE stt_cong_doan = #{sttCongDoan}
AND ma_du_an = #{maDuAn}
AND ma_nhan_vien = #{maNhanVien}
